            "as) +\n                                    BatchNormActivation(C + 1, In(\"DC\", C " +
            "+ 1), p.Activation) +\n                                    strSE +\n              " +
            "                      BatchNorm(C + 2, In(\"C\", C + 2)) +\n                       " +
            "             DropPathAdd(A + 1, In(\"B\", C + 2) + \",\" + strOutputLayer));\n\n      " +
